<script>
  import { onMount, afterUpdate, createEventDispatcher } from 'svelte'
  import { options, msg, lazy } from '../lib/stores'
  import request from '../lib/request'
  import emotFn from '../lib/emot'
  import Emotion from '../../../assets/svg/Emotion.svg'
  import Loading from '../../../assets/svg/Loading.svg'
  import Setting from '../../../assets/svg/Setting.svg'
  import Refresh from '../../../assets/svg/Refresh.svg'
  import { translate } from '../i18n'

  let D = $options
  const dispatch = createEventDispatcher()

  export let cancel = false,
    pid = '',
    rid = '',
    wordLimit = 0

  let wordLimitContent = wordLimit.content
  $: {
    wordLimitContent = wordLimit.content
  }

  // 普通变量
  const textStr = 'text'
  const nickStr = 'nick'
  const mailStr = 'mail'
  const siteStr = 'site'
  const contentStr = 'content'
  const mailReg = /^\w+([-.]\w+)*@\w+([-.]\w+)*(\.[a-z]{2,5})+$/

  function isUrl(str) {
    try {
      if (/^https?:\/\//.test(str) && /([A-Za-z\d]{1,30}\.)+[A-Za-z\d]{2,5}$/.test(new URL(str).hostname)) {
        return true
      }
      // eslint-disable-next-line no-empty
    } catch (error) {}
    return false
  }

  // svelte变量
  let storage = localStorage.discuss
  let isEmot = false
  let emotIndex = 0
  let emotMaps = {}
  let emotAll = {}
  let isSend = false
  let isLegal = false
  const inputs = [
    {
      key: nickStr,
      locale: translate(nickStr),
      type: textStr
    },
    {
      key: mailStr,
      locale: translate(mailStr),
      type: 'e' + mailStr
    },
    {
      key: siteStr,
      locale: translate(siteStr),
      type: textStr
    }
  ]
  let metas = {
    nick: { value: '', is: false },
    mail: { value: '', is: false },
    site: { value: '', is: true },
    content: { value: '', is: false }
  }

  onMount(() => {
    initInfo()
    getEmot()
  })

  afterUpdate(() => {
    MetasChange()
    $lazy()
  })

  function initInfo() {
    try {
      storage = JSON.parse(storage) || {}
      for (const [k, v] of Object.entries(storage)) {
        metas[k].value = v || ''
      }
    } catch (error) {
      storage = {}
    }
  }

  async function getEmot() {
    const emot = D.emotMaps
    if (/\.json$/.test(emot)) {
      emotMaps = await request({ url: emot, method: 'GET' })
    } else if (!emot) {
      emotMaps = emotFn(D.emotCDN)
    } else {
      emotMaps = emot
    }
    getEmotAll()
  }

  function getEmotAll() {
    try {
      for (const e in emotMaps) {
        const type = emotMaps[e].type
        if (type === textStr) continue
        const items = emotMaps[e].items
        emotAll = { ...emotAll, ...items }
      }
    } catch (error) {
      // eslint-disable-next-line no-console
      console.log(error)
    }
  }

  function SaveInfo() {
    for (const [k, v] of Object.entries(metas)) {
      storage[k] = v.value.trim()
    }
    localStorage.discuss = JSON.stringify(storage)
  }

  function onInput() {
    SaveInfo()
    MetasChange()
  }

  let lastEditRange
  function getCursor() {
    const sel = window.getSelection()
    if (sel.rangeCount < 0) {
      lastEditRange = document.createRange()
      return
    }

    lastEditRange = sel.getRangeAt(0)
  }

  /**
   * @param {String} key 表情名(描述)
   * @param {String} value 表情值(内容或地址)
   * @param {String} type 表情类型(text or image)
   */
  let textareaDOM
  // eslint-disable-next-line max-statements
  function onClickEmot(key, value, type) {
    textareaDOM.focus()
    const sel = window.getSelection()
    if (lastEditRange) {
      // 清除所有光标并添加最后光标编辑的状态
      sel.removeAllRanges()
      sel.addRange(lastEditRange)
    }

    let emojiEl

    if (type === textStr) {
      emojiEl = document.createTextNode(value)
    } else {
      emojiEl = document.createElement('img')
      emojiEl.src = emotAll[key]
      emojiEl.className = 'D-comment-emot'
      emojiEl.alt = key
    }

    // 不存在光标，则获取光标，并将光标移动至最后
    if (!lastEditRange) {
      getCursor()
      lastEditRange.selectNodeContents(textareaDOM)
      lastEditRange.collapse(false)
      sel.removeAllRanges()
      sel.addRange(lastEditRange)
    }

    // 如果光标没有重叠，则代表光标选择了一部分内容，需要删除光标再插入表情
    if (!lastEditRange.collapsed) lastEditRange.deleteContents()

    lastEditRange.insertNode(emojiEl)

    // 让光标保持在插入表情的后面, true 表示保持在前面
    lastEditRange.collapse(false)

    metas.content.value = textareaDOM.innerHTML
    // 保存
    SaveInfo()
  }

  function MetasChange() {
    try {
      const { nick, mail, site, content } = metas
      for (const [k, v] of Object.entries(metas)) {
        const len = v.value.length
        const word = wordLimit[k]
        let condition = true
        if (k === nickStr) condition = len > 1
        if (k === mailStr) condition = mailReg.test(v.value)
        if (k === siteStr) condition = len === 0 ? true : isUrl(v.value)
        if (k === contentStr) condition = len > 1

        // 如果word的参数不为0，则判断输入框内容长度是否符合规定
        if (word) condition = condition && len <= word

        condition ? (metas[k].is = true) : (metas[k].is = false)
      }
      isLegal = nick.is && mail.is && site.is && content.is
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error(error)
    }
  }

  // eslint-disable-next-line max-statements
  async function onSend() {
    try {
      if (!isSend && !isLegal) return
      const comment = {
        type: 'COMMIT_COMMENT',
        nick: metas.nick.value,
        mail: metas.mail.value,
        site: metas.site.value,
        content: metas.content.value,
        path: D.path,
        pid,
        rid
      }
      isSend = true

      const token = localStorage.DToken
      if (token) comment.token = token
      const result = await request({
        url: D.serverURLs,
        data: comment
      })

      if (!result.data && result.msg.includes('login')) {
        $msg({ type: 'error', text: translate('pleaseLogin') })
      }

      if (Array.isArray(result.data)) {
        if (!result.data.length) $msg({ type: 'success', duration: 5000, text: translate('commentsAudit') })

        dispatch('submitComment', { comment: result.data, pid })
        metas.content.value = ''
        SaveInfo()
      }
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error('Comment failure:', error)
      $msg({ type: 'error', text: translate('sendError') })
    } finally {
      isSend = false
    }
  }
</script>

<div class="D-submit">
  <div class="D-input">
    {#each inputs as i}
      <input
        bind:value={metas[i.key].value}
        class={metas[i.key].is ? '' : 'D-error'}
        name={i.key}
        placeholder={i.locale}
        on:input={(e) => (e.target.type = i.type)}
        on:input={onInput}
      />
    {/each}
    <div
      name={contentStr}
      class="D-input-content {metas.content.is ? '' : 'D-error'}"
      placeholder={D.ph}
      on:input={function () {
        metas.content.value = this.innerHTML
        onInput()
      }}
      on:click={getCursor}
      on:keyup={getCursor}
      bind:this={textareaDOM}
      bind:innerHTML={metas.content.value}
      contenteditable
    />

    {#if wordLimitContent}
      <span class="D-text-number">
        {metas.content.value.length}
        {#if wordLimitContent}
          <span class={metas.content.value.length > wordLimitContent && 'D-text-number-illegal'}
            >{'/ ' + wordLimitContent}
          </span>
        {/if}
      </span>
    {/if}
  </div>
  <div class="D-actions D-select-none">
    <div class="D-actions-left">
      <div class="D-emot-btn" on:click={() => (isEmot = !isEmot)}>
        <Emotion />
      </div>
      {#if !cancel}
        <div class="D-setting-btn" on:click={() => dispatch('onSetting')}><Setting /></div>
        <div class="D-refresh-btn" on:click={() => dispatch('onRefresh')}><Refresh /></div>
      {/if}
    </div>

    <div class="D-actions-right">
      <!-- 取消回复 -->
      {#if cancel}
        <button class="D-cancel D-btn D-btn-main" on:click={() => dispatch('onCancel', true)}
          >{translate('cancel')}</button
        >
      {/if}

      <button class="D-send D-btn D-btn-main" on:click={onSend} disabled={isSend || !isLegal}>
        {#if isSend && isLegal}
          <Loading />
        {:else}
          {translate('send')}
        {/if}
      </button>
    </div>
  </div>
  {#if isEmot}
    <div class="D-emot">
      {#each Object.entries(emotMaps) as [emotKey, emotValue], index}
        <ul class="D-emot-items {index === emotIndex ? 'D-emot-items-active' : ''}">
          {#each Object.entries(emotValue.items) as [iKey, iValue]}
            <li class="D-emot-item" on:click={onClickEmot(iKey, iValue, emotValue.type)}>
              {#if emotValue.type === 'text'}
                <span title={iKey}>{iValue}</span>
              {:else}
                <img class="D-comment-emot" src={D.imgLoading} d-src={iValue} alt={iKey} title={iKey} />
              {/if}
            </li>
          {/each}
        </ul>
      {/each}

      <div class="D-emot-packages">
        {#each Object.entries(emotMaps) as [emotKey, emotValue], index}
          <span on:click={() => (emotIndex = index)} class={index === emotIndex ? 'D-emot-package-active' : ''}
            >{@html emotKey}</span
          >
        {/each}
      </div>
    </div>
  {/if}
</div>

